query:
ALTER TABLE diets ADD COLUMN preferredFoods JSON DEFAULT NULL;
ALTER TABLE diets ADD COLUMN allergies JSON DEFAULT NULL;
ALTER TABLE diets ADD COLUMN fastingProtocol VARCHAR(20) DEFAULT NULL;
ALTER TABLE diets ADD COLUMN folderId INT DEFAULT NULL;

ALTER TABLE meals ADD COLUMN enabled INT NOT NULL DEFAULT 1;

ALTER TABLE foods ADD COLUMN sortOrder INT NOT NULL DEFAULT 0;

CREATE TABLE IF NOT EXISTS supplements (
  id INT AUTO_INCREMENT PRIMARY KEY,
  dietId INT NOT NULL,
  name VARCHAR(255) NOT NULL,
  dose VARCHAR(100) DEFAULT NULL,
  timing VARCHAR(100) DEFAULT NULL,
  notes TEXT DEFAULT NULL,
  sortOrder INT NOT NULL DEFAULT 0
);

CREATE TABLE IF NOT EXISTS folders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  userId INT NOT NULL,
  name VARCHAR(255) NOT NULL,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS custom_foods (
  id INT AUTO_INCREMENT PRIMARY KEY,
  userId INT NOT NULL,
  name VARCHAR(255) NOT NULL,
  caloriesPer100g INT NOT NULL,
  proteinPer100g INT NOT NULL,
  carbsPer100g INT NOT NULL,
  fatsPer100g INT NOT NULL,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS diet_instructions (
  id INT AUTO_INCREMENT PRIMARY KEY,
  dietId INT NOT NULL,
  hungerManagement TEXT DEFAULT NULL,
  portionControl TEXT DEFAULT NULL,
  weighingFood TEXT DEFAULT NULL,
  weekendGuidelines TEXT DEFAULT NULL,
  healthIndications TEXT DEFAULT NULL,
  professionalNotes TEXT DEFAULT NULL
);

